61	function shuffleLeads(arr: Lead[]): Lead[] {
62	  const a = [...arr];
63	  for (let i = a.length - 1; i > 0; i--) {
64	    const j = Math.floor(Math.random() * (i + 1));
65	    [a[i], a[j]] = [a[j], a[i]];
66	  }
67	  return a;
68	}
